// optional import of sdk modules
import { execution } from '@dynatrace-sdk/automation-utils';
import { EventIngest, EventIngestEventType, eventsClient } from '@dynatrace-sdk/client-classic-environment-v2';
import { getEnvironmentUrl } from "@dynatrace-sdk/app-environment";

export default async function ({ executionId }) {


  const { input } = await fetch(`/platform/automation/v1/executions/${executionId}`).then((res) => res.json());

  console.log(input.entitySelector)


  let final: string | undefined | null;
  if (input.entitySelector == "") {
      const xevent: EventIngest = {
        eventType: EventIngestEventType.CustomInfo,
        title: input.title,
        properties: input.properties, 
      };
      console.log(xevent)
      const result = await eventsClient.createEvent({ body: xevent })
      while (final  === undefined  || final  === null || final  === "") {
          const data = await eventsClient.getEvents({
            eventSelector: "correlationId(\""+result.eventIngestResults[0].correlationId+"\")"
          });
          final = data.events[0]
      }


      return final;

  } else {
      const xevent: EventIngest = {
            eventType: EventIngestEventType.CustomInfo,
            title: input.title,
            entitySelector: input.entitySelector,
            properties: input.properties,
      };
      console.log(xevent)
      const result = await eventsClient.createEvent({ body: xevent })
      while (final  === undefined  || final  === null || final  === "") {
          const data = await eventsClient.getEvents({
            eventSelector: "correlationId(\""+result.eventIngestResults[0].correlationId+"\")"
          });
          final = data.events[0]
      }


      return final;
  }



}
